def binary_search(arr, key):
    left = 0
    right = len(arr) - 1

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == key:
            return mid  # Element found
        elif arr[mid] < key:
            left = mid + 1  # Search right half
        else:
            right = mid - 1  # Search left half

    return -1  # Element not found

#include <stdio.h>

void insert(int arr[], int *n, int pos, int value, int capacity) {
    if (*n >= capacity) {
        printf("Array is full\n");
        return;
    }
    if (pos < 0 || pos > *n) {
        printf("Invalid position\n");
        return;
    }
    // Shift elements to the right
    for (int i = *n; i > pos; i--) {
        arr[i] = arr[i-1];
    }
    arr[pos] = value;
    (*n)++;
}

class Stack {
    private int top;
    private int[] array;
    private int capacity;

    public Stack(int size) {
        capacity = size;
        array = new int[capacity];
        top = -1;
    }

    public void push(int value) {
        if (top >= capacity - 1) {
            System.out.println("Stack Overflow");
            return;
        }
        array[++top] = value;
    }

    public int pop() {
        if (top < 0) {
            System.out.println("Stack Underflow");
            return -1;
        }
        return array[top--];
    }

    public int peek() {
        if (top < 0) return -1;
        return array[top];
    }

    public boolean isEmpty() {
        return top < 0;
    }
}
